ItemConfig = {}
ItemConfig.Items = {}
function ItemConfig:loadConfig()
    local configs = FileUtil.getConfigFromCsv("setting/Items.csv", 3)
    for _, config in pairs(configs) do
        local item = {
            id = tonumber(config.id),
            itemId = tonumber(config.itemId),
            name = config.name,
            desc = config.desc,
            tab = tonumber(config.tab)
        }
        self.Items[item.id] = item
    end
end

function ItemConfig:getItemsByTab(tab)
    local result = {}
    for _, item in pairs(self.Items) do
        if item.tab == tonumber(tab) then
            table.insert(result, item)
        end
    end
    return result
end

function ItemConfig:getItemIdById(id)
    for _, item in pairs(self.Items) do
        if item.id == tonumber(id) then
            return item.itemId
        end
    end
    return id
end

function ItemConfig:getItemById(id)
    return self.Items[tonumber(id)]
end

function ItemConfig:getItemNameById(id)
    for _, item in pairs(self.Items) do
        if item.itemId == tonumber(id) then
            return item.name
        end
    end
end